return msg;

if (!flow.get('dxccReady')) {
    node.status({ fill: 'grey', shape: 'dot', text: 'Paused — reference data loading...' });
    return null;
}

var prefixMap = flow.get('dxccPrefixMap') || {};
var exceptions = flow.get('dxccExceptions') || {};
var seedNames = flow.get('dxccSeedNames') || {};

if (Object.keys(prefixMap).length === 0) {
    node.status({ fill: 'yellow', shape: 'dot', text: 'Waiting for cty.xml...' });
    return null;
}

function resolveDXCC(call) {
    call = call.toUpperCase();
    if (exceptions[call]) return exceptions[call];
    var parts = call.split('/');
    var bestDxcc = null, bestLen = 0;
    parts.forEach(function (part) {
        if (part.length <= 2) return;
        for (var len = Math.min(5, part.length); len >= 1; len--) {
            var pfx = part.substring(0, len);
            if (prefixMap[pfx]) {
                if (len > bestLen) { bestLen = len; bestDxcc = prefixMap[pfx]; }
                break;
            }
        }
    });
    return bestDxcc || parts[0].substring(0, 4);
}

var spot = msg.spot;
if (!spot) return null;

var blacklist = flow.get('dxccBlacklist') || [];
if (blacklist.indexOf(spot.call) !== -1) {
    node.status({ fill: 'grey', shape: 'ring', text: spot.call + ' blacklisted' });
    return null;
}

var band = (spot.band || '').toString().toUpperCase().trim();
if (!band) return null;

var entityWorked = flow.get('entityWorked') || {};
if (Object.keys(entityWorked).length === 0) {
    node.status({ fill: 'yellow', shape: 'dot', text: 'Waiting for Club Log data...' });
    return null;
}

var seedKey = resolveDXCC(spot.call);
spot.dxcc = seedKey;
spot.entity = seedNames[seedKey] || seedKey;

if (!seedNames[seedKey]) {
    node.status({ fill: 'grey', shape: 'ring', text: spot.call + ' unknown DXCC: ' + seedKey });
    return null;
}

var ew = entityWorked[seedKey];
var bw = ew ? ew[band] : null;

var entityExists = !!ew && Object.keys(ew).length > 0;
var bandWorked = !!(bw && (bw.confirmed || bw.unconfirmed));
var bandConfirmed = !!(bw && bw.confirmed);

function getModeCat(m) {
    if (!m) return null;
    var u = m.toUpperCase();
    if (u === 'CW') return 'cw';
    if (u === 'FT8' || u === 'FT4' || u === 'RTTY' || u === 'PSK31' || u === 'DATA' || u === 'JS8') return 'data';
    if (u === 'USB' || u === 'LSB' || u === 'SSB' || u === 'AM' || u === 'FM' || u === 'PHONE') return 'phone';
    return null;
}
var modeCat = getModeCat(spot.mode);
var modeWorkedMap = flow.get('dxccModeWorked') || {};
var modeEntry = modeWorkedMap[seedKey];
var modeAlreadyWorked = !!(modeEntry && modeCat && modeEntry[modeCat]);

// Mode filter — applies to all alerts for this spot
var modeCatForFilter = getModeCat(spot.mode);
if (modeCatForFilter === 'cw' && flow.get('filterModeCW') === false) return null;
if (modeCatForFilter === 'phone' && flow.get('filterModePhone') === false) return null;
if (modeCatForFilter === 'data' && flow.get('filterModeData') === false) return null;

// Band filter — applies to all alerts for this spot
var filterBands = flow.get('filterBands');
if (filterBands && Object.keys(filterBands).length > 0 && !filterBands[band]) {
    node.status({ fill: 'grey', shape: 'ring', text: spot.call + ' filtered (' + band + ')' });
    return null;
}

var filterNewDxcc = flow.get('filterNewDxcc');
var filterNewBand = flow.get('filterNewBand');
var filterNewBandUnconf = flow.get('filterNewBandUnconf');
var filterNewMode = flow.get('filterNewMode');
var filterNewModeUnconf = flow.get('filterNewModeUnconf');

var confStatus = '\u2014';
if (bw) confStatus = bw.confirmed ? 'confirmed \u2713' : 'unconfirmed \u2717';

// Build independent alerts
var alerts = [];

if (!entityExists) {
    // NEW DXCC — exclusive, no band/mode alerts on top
    if (filterNewDxcc !== false) {
        alerts.push({ type: 'NEW_DXCC', color: '#f85149', label: 'NEW DXCC', unconf: false });
    }
} else {
    // NEW BAND (confirmed) or NEW BAND unconfirmed
    if (!bandWorked) {
        if (filterNewBand !== false)
            alerts.push({ type: 'NEW_BAND', color: '#58a6ff', label: 'NEW BAND', unconf: false });
    } else if (bandWorked && !bandConfirmed) {
        if (filterNewBandUnconf !== false)
            alerts.push({ type: 'NEW_BAND_UNCONF', color: '#2d6aad', label: '? BAND', unconf: true });
    }
    // NEW MODE (confirmed) or NEW MODE unconfirmed
    if (modeCat && !modeAlreadyWorked) {
        if (filterNewMode !== false)
            alerts.push({ type: 'NEW_MODE', color: '#e3b341', label: 'NEW MODE', unconf: false });
    } else if (modeCat && modeAlreadyWorked) {
        // mode worked but check if this specific band+mode slot is unconfirmed
        var bwMode = bw;
        if (bwMode && !bwMode.confirmed) {
            if (filterNewModeUnconf !== false)
                alerts.push({ type: 'NEW_MODE_UNCONF', color: '#9a7030', label: '? MODE', unconf: true });
        }
    }
}

if (alerts.length === 0) {
    node.status({ fill: 'grey', shape: 'ring', text: spot.call + ' worked (' + spot.entity + ' ' + band + ')' });
    return null;
}

// Node status — show all alert types
var statusFill = alerts[0].color === '#58a6ff' ? 'blue' :
    alerts[0].color === '#e3b341' ? 'yellow' : 'red';
node.status({
    fill: statusFill, shape: 'dot',
    text: alerts.map(function (a) { return a.label; }).join('+') + ': ' + spot.call + ' ' + spot.entity + ' ' + band
});

// Fire one msg per alert
alerts.forEach(function (a) {
    var alertObj = {
        type: a.type, color: a.color, label: a.label, unconf: a.unconf,
        call: spot.call, entity: spot.entity, dxcc: seedKey,
        band: band, mode: spot.mode, freqKHz: spot.freqKHz, freqMHz: spot.freqMHz,
        spotter: spot.spotter, comment: spot.comment, confStatus: confStatus,
        time: new Date().toLocaleTimeString()
    };
    node.send({ spot: spot, alert: alertObj, payload: alertObj });
});
return null;

