function child(block, tag) {
    var re = new RegExp('<' + tag + '>([^<]*)<\/' + tag + '>');
    var m = block.match(re);
    return m ? m[1].trim() : '';
}

function isCurrent(block) {
    var end = child(block, 'end');
    if (!end || end === '') return true;
    try { return new Date(end.replace(' ', 'T') + 'Z') >= new Date(); } catch(e) { return true; }
}

var prefixMap   = {};  // prefix string -> ADIF number (string)
var entityNames = {};  // ADIF number   -> entity name
var exceptions  = {};  // callsign      -> ADIF number (string)

// Parse <entities>
var entRe = /<entity\b[^>]*>([\s\S]*?)<\/entity>/g;
var em;
while ((em = entRe.exec(xml)) !== null) {
    var b = em[1];
    var adif    = child(b, 'adif');
    var name    = child(b, 'name');
    var deleted = child(b, 'deleted').toUpperCase();
    if (adif && name && deleted !== 'TRUE') {
        entityNames[adif] = name;
    }
}

// Parse <prefixes>
var pfxRe = /<prefix\b[^>]*>([\s\S]*?)<\/prefix>/g;
var pm;
while ((pm = pfxRe.exec(xml)) !== null) {
    var b = pm[1];
    var call = child(b, 'call').toUpperCase();
    var adif = child(b, 'adif');
    if (!call || !adif) continue;
    if (!isCurrent(b)) continue;
    prefixMap[call] = adif;
}

// Parse <exceptions>
var excRe = /<exception\b[^>]*>([\s\S]*?)<\/exception>/g;
var xm;
while ((xm = excRe.exec(xml)) !== null) {
    var b = xm[1];
    var call = child(b, 'call').toUpperCase();
    var adif = child(b, 'adif');
    if (!call || !adif) continue;
    if (!isCurrent(b)) continue;
    exceptions[call] = adif;
}

var pfxCount = Object.keys(prefixMap).length;
var excCount = Object.keys(exceptions).length;
var entCount = Object.keys(entityNames).length;

if (pfxCount < 100) {
    node.error('Too few prefixes: ' + pfxCount);
    node.status({fill:'red', shape:'dot', text:'Parse failed'});
    return null;
}

flow.set('dxccPrefixMap',  prefixMap);
flow.set('dxccExceptions', exceptions);
flow.set('dxccSeedNames',  entityNames);

node.status({fill:'green', shape:'dot',
