var CONNECTED_MS = 5 * 60 * 1000;
var STALE_MS = 15 * 60 * 1000;
var now = Date.now();

var cs = flow.get('clusterStatus') || {};

Object.keys(srcMap).forEach(function (key) {
    if (!cs[key]) {
        cs[key] = { name: srcMap[key], host: key, count: 0, lastSpot: '', lastSpotTs: 0, connected: false, reconnecting: false };
    }
    var age = now - (cs[key].lastSpotTs || 0);
    if (cs[key].lastSpotTs === 0) {
        cs[key].connected = false;
        cs[key].reconnecting = false;
    } else if (age < CONNECTED_MS) {
        cs[key].connected = true;
        cs[key].reconnecting = false;
    } else if (age < STALE_MS) {
        cs[key].connected = false;
        cs[key].reconnecting = true;
    } else {
        cs[key].connected = false;
        cs[key].reconnecting = false;
    }
});

