// ─────────────────────────────────────────────────────────────
// Handles ALL clusters feeding into this single node.
// A) Login  — detects 'login:' and replies VU2CPL on same session
// B) Parse  — turns DX spot lines into SmartSDR spot add commands
// C) Status — tracks per-source spot count + last spot time
// D) Dedup  — suppresses duplicate callsign+freq within 60 seconds
// ─────────────────────────────────────────────────────────────

var line = (msg.payload || '').trim();
var src = msg.topic || 'unknown';

// ── Source key map (topic → display name) ─────────────────────
var srcMap = {
    'cluster1': 'N2WQ',
    'cluster2': 'VU2OY',
    'cluster3': 'VU2CPL',
    'cluster4': 'VE7CC'
};

// ── A) LOGIN ─────────────────────────────────────────────────
if (line.toLowerCase().includes('login:') ||
    line.toLowerCase().includes('please login')) {
    node.status({ fill: 'blue', shape: 'dot', text: src + ' → login sent' });
    return [
        { payload: 'VU2CPL\r\n', _session: msg._session },
        null, null
    ];
}

// ── Skip non-DX lines ─────────────────────────────────────────
if (!line.startsWith('DX de')) {
    node.status({ fill: 'grey', shape: 'ring', text: '[' + src + '] ' + line.substring(0, 50) });
    return [null, null, null];
}

// ── B) PARSE ─────────────────────────────────────────────────
var re = /^DX de\s+([A-Z0-9\/\-#]+):\s+([\d.]+)\s+([A-Z0-9\/\-#]+)\s*(.*?)\s*(\d{4}Z?)?\s*$/i;
var m = line.match(re);
if (!m) {
    node.status({ fill: 'yellow', shape: 'dot', text: 'no match: ' + line.substring(0, 45) });
    return [null, null, null];
}

var spotter = m[1].toUpperCase();
var freqKHz = parseFloat(m[2]);
var dxCall = m[3].toUpperCase();
var comment = (m[4] || '').trim();
var freqMHz = (freqKHz / 1000).toFixed(6);

var now = Date.now();

// ── C) CLUSTER STATUS — before dedup so all spots counted ─────
var cs = flow.get('clusterStatus') || {};
if (!cs[src]) cs[src] = { name: srcMap[src] || src, host: src, count: 0, lastSpot: '', lastSpotTs: 0, connected: false, reconnecting: false };
cs[src].count++;
cs[src].lastSpot = new Date().toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', second: '2-digit' });
cs[src].lastSpotTs = now;
cs[src].connected = true;
cs[src].reconnecting = false;
flow.set('clusterStatus', cs);

// ── D) DEDUP ─────────────────────────────────────────────────
var dedup = flow.get('dedup') || {};
var dedupKey = dxCall + '_' + Math.round(freqKHz);

if (dedup[dedupKey] && (now - dedup[dedupKey]) < 60000) {
    node.status({ fill: 'grey', shape: 'ring', text: 'dup skip: ' + dxCall + ' (' + src + ')' });
    return [null, null, null];
}
dedup[dedupKey] = now;
Object.keys(dedup).forEach(function (k) {
    if (now - dedup[k] > 120000) delete dedup[k];
});
flow.set('dedup', dedup);

// ── Mode detection ────────────────────────────────────────────
function getMode(khz, cmt) {
    var c = cmt.toUpperCase();
    if (c.match(/\bFT8\b/)) return 'Data';
    if (c.match(/\bFT4\b/)) return 'Data';
    if (c.match(/\bRTTY\b/)) return 'Data';
    if (c.match(/\bPSK\b/)) return 'Data';
    if (c.match(/\bDIGI\b/)) return 'Data';
    if (c.match(/\bDATA\b/)) return 'Data';
    if (c.match(/\bCW\b/)) return 'CW';
    if (c.match(/\bSSB\b/)) return (khz < 10000) ? 'LSB' : 'USB';
    if (c.match(/\bUSB\b/)) return 'USB';
    if (c.match(/\bLSB\b/)) return 'LSB';
    if (c.match(/\bAM\b/)) return 'AM';
    if (c.match(/\bFM\b/)) return 'FM';
    var ft8 = [1840, 3573, 7074, 10136, 14074, 18100, 21074, 24915, 28074, 50313];
    for (var f = 0; f < ft8.length; f++) {
        if (Math.abs(khz - ft8[f]) <= 3) return 'Data';
    }
    var cw = [[1800, 1840], [3500, 3600], [7000, 7040], [10100, 10150],
    [14000, 14070], [18068, 18110], [21000, 21070],
    [24890, 24920], [28000, 28070]];
    for (var i = 0; i < cw.length; i++) {
        if (khz >= cw[i][0] && khz <= cw[i][1]) return 'CW';
    }
    return (khz < 10000) ? 'LSB' : 'USB';
}

var mode = getMode(freqKHz, comment);

// ── Sequence counter ──────────────────────────────────────────
var seq = flow.get('spotSeq') || 7000;
seq++;
flow.set('spotSeq', seq);

var ts = Math.floor(Date.now() / 1000);

// ── Build SmartSDR command ────────────────────────────────────
var cmd = 'C' + seq + '|spot add' +
    ' rx_freq=' + freqMHz +
    ' callsign=' + dxCall +
    ' mode=' + mode +
    ' comment=' + (comment || 'DX') +
    ' spotter_callsign=' + spotter +
    ' timestamp=' + ts +
    ' color=#FF00FCCC' +
    ' priority=2' +
    ' lifetime_seconds=1200' +
    ' source=DX-Spot' +
    '\n';

node.status({
    fill: 'green', shape: 'dot',
    text: '[' + src + '] C' + seq + ' ' + dxCall + ' ' + freqMHz + ' ' + mode
});

var statusMsg = {
    topic: 'cluster_status',
    payload: flow.get('clusterStatus') || {}
};

return [
    null,
    { payload: cmd, spot: { seq: seq, dxCall: dxCall, freqKHz: freqKHz, freqMHz: freqMHz, mode: mode, spotter: spotter, comment: comment, src: src } },
    statusMsg
];
